   440→  /** Walk up from a path to find the nearest project root */
   441→  private findProjectRoot(dir: string): string {
   442→    const markers = ['.git', 'package.json', 'Cargo.toml', 'go.mod', 'pyproject.toml', 'pom.xml'];
   443→    let current = dir;
   444→    const home = getUserHome();
   445→    while (current.length > home.length) {
   446→      for (const marker of markers) {
   447→        try {
   448→          fs.statSync(`${current}/${marker}`);
   449→          return current;
   450→        } catch { /* continue */ }
   451→      }
   452→      const parent = current.slice(0, current.lastIndexOf('/'));
   453→      if (parent === current) break;
   454→      current = parent;
   455→    }
   456→    return dir; // fallback to the common root itself
   457→  }
