   692→  private async handleAssistantText(sessionId: string, text: string): Promise<void> {
   693→    const session = this.registry.getSession(sessionId);
   694→    if (!session?.threadId) return;
   695→    if (session.filterLevel === 'silent') return;
   696→    // Skip SDK sessions — their output is routed via stream events, not transcript
   697→    if (session.source === 'sdk') return;
   698→
   699→    const previous = this.lastAssistantText.get(sessionId);
   700→    if (previous && previous.text === text && Date.now() - previous.at < 15_000) {
   701→      console.log(`[router] Skip duplicate assistant text for ${sessionId.slice(0, 8)}`);
   702→      return;
   703→    }
   704→    this.lastAssistantText.set(sessionId, { text, at: Date.now() });
   705→
   706→    const brand = getAgentBrand(session.agent);
   707→    const author = { name: brand.label, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) };
   708→
   709→    // Discord embed description limit is 4096 chars
   710→    const truncated = text.length > 3800
   711→      ? text.slice(0, 3800) + `\n*[${text.length} chars total]*`
   712→      : text;
   713→
   714→    await this.discord.sendToThread(session.threadId, {
   715→      embed: {
   716→        author,
   717→        description: truncated,
   718→        color: brand.color,
   719→      },
   720→    });
   721→  }
