   764→  private async routeToIM(session: CLISession, msg: EventMsg): Promise<void> {
   765→    if (!session.threadId) return;
   766→
   767→    // Track context for title updates (before filter — track all events)
   768→    this.extractContext(session, msg);
   769→    await this.maybeUpdateTitle(session);
   770→
   771→    const event = msg.event;
   772→    const level = session.filterLevel;
   773→
   774→    // Extract tool name for filter decision
   775→    const toolName = (event === 'tool_use' || event === 'tool_result')
   776→      ? ((msg.data as { tool?: string; name?: string }).tool || (msg.data as { name?: string }).name)
   777→      : undefined;
   778→
   779→    // Filter check
   780→    if (!this.shouldForward(event, level, toolName)) return;
   781→
   782→    // In summary mode, tool_result gets a compact one-line rendering
   783→    if (level === 'summary' && event === 'tool_result') {
   784→      const d = msg.data as { tool?: string; input?: unknown; is_error?: boolean };
   785→      const inp = this.parseInput(d.input);
   786→      let summary = '';
   787→      if (inp.command) summary = String(inp.command).slice(0, 80);
   788→      else if (inp.file_path) summary = String(inp.file_path);
   789→      else if (inp.pattern) summary = String(inp.pattern);
   790→      const icon = d.is_error ? '\u274c' : '\u2705';
   791→      await this.discord.sendToThread(session.threadId, `${icon} **${d.tool || 'tool'}** ${summary}`);
   792→      return;
   793→    }
   794→
   795→    const rendered = this.renderEvent(event, msg.data, session.agent);
   796→    await this.discord.sendToThread(session.threadId, rendered);
   797→  }
