   981→  private async handleThreadCommand(session: CLISession, command: string): Promise<void> {
   982→    const parts = command.split(/\s+/);
   983→    const cmd = this.normalizeCommand(parts[0].toLowerCase());
   984→    const mode = this.getSessionInteractionMode(session);
   985→
   986→    switch (cmd) {
   987→      case '!help': {
   988→        if (session.threadId) {
   989→          await this.discord.sendToThread(session.threadId, [
   990→            `**模式:** ${mode.label}`,
   991→            mode.hint,
   992→            '',
   993→            '**命令:**',
   994→            '`!help` — 显示这份帮助',
   995→            '`!distill` — 生成 MindKeeper checkpoint（`dst-*`），不可用时回退到本地摘要',
   996→            '`恢复 <dst-id>` / `继续 <dst-id>` — 读取恢复口令，不再误发给 SDK',
   997→            '`!filter full|summary|compact|silent` — 切换过滤级别',
   998→            '`!info` — 查看当前 session 信息',
   999→            '`!model <name>` — 切换 SDK session 的 model',
  1000→            '`!models` — 列出可用 model（来源于本地 MMS routes）',
  1001→            '`!provider <id>` — 覆盖 SDK session 的 provider',
  1002→            '`!cd <path-or-name>` — 修改后续 SDK turn 的 cwd',
  1003→            '`!fork [prompt]` — 从当前 session fork',
  1004→            '`!start <prompt>` — 在当前 cwd 启动新的 SDK session',
  1005→            '`!abort` — 中止正在运行的 SDK turn',
  1006→            '`!done` / `!close` — 结束并归档当前 thread',
  1007→            '',
  1008→            '文本命令支持 `!` / `/` / 全角 `！` / `／` 前缀。',
  1009→          ].join('\n'));
  1010→        }
  1011→        break;
  1012→      }
  1013→      case '!distill': {
  1014→        if (session.threadId) {
  1015→          await this.discord.sendToThread(session.threadId, await this.buildDistillMessage(session));
  1016→        }
  1017→        break;
  1018→      }
  1019→      case '!filter': {
  1020→        const level = parts[1] as FilterLevel;
  1021→        if (!['full', 'summary', 'compact', 'silent'].includes(level)) {
  1022→          if (session.threadId) {
  1023→            await this.discord.sendToThread(session.threadId, '用法: `!filter full|summary|compact|silent`');
  1024→          }
  1025→          return;
  1026→        }
  1027→        this.registry.setFilterLevel(session.sessionId, level);
  1028→        if (session.threadId) {
  1029→          await this.discord.sendToThread(session.threadId, `过滤级别已切换为 **${level}**`);
  1030→        }
  1031→        break;
  1032→      }
  1033→      case '!info': {
  1034→        if (session.threadId) {
  1035→          await this.discord.sendToThread(session.threadId, [
  1036→            `**Session:** \`${session.sessionId.slice(0, 8)}\``,
  1037→            `**Project:** ${session.project}`,
  1038→            `**Branch:** ${session.branch}`,
  1039→            `**Directory:** \`${collapseHome(session.cwd)}\``,
  1040→            `**Filter:** ${session.filterLevel}`,
  1041→            `**Status:** ${session.status}`,
  1042→            `**Source:** ${session.source}`,
  1043→            `**Mode:** ${mode.label}`,
  1044→            `**PID:** ${session.pid}`,
  1045→            `**Reply:** ${mode.hint}`,
  1046→          ].join('\n'));
  1047→        }
  1048→        break;
  1049→      }
  1050→      case '!model': {
  1051→        const newModel = parts[1];
  1052→        if (!newModel) {
  1053→          if (session.threadId) {
  1054→            await this.discord.sendToThread(session.threadId, `当前 model: **${session.model || 'default'}**\n用法: \`!model <name-or-prefix>\``);
  1055→          }
  1056→          return;
