  1102→        }
  1103→        break;
  1104→      }
  1105→
  1106→      case '!provider': {
  1107→        const newProvider = parts[1];
  1108→        if (!newProvider) {
  1109→          if (session.threadId) {
  1110→            await this.discord.sendToThread(session.threadId, `当前 provider: **${session.provider || 'default'}**\n用法: \`!provider <provider-id>\``);
