  1114→        session.provider = newProvider;
  1115→        this.store.setSession(session);
  1116→        if (session.threadId) {
  1117→          await this.discord.sendToThread(session.threadId, `Provider → **${newProvider}**`);
  1118→        }
  1119→        break;
  1120→      }
  1121→
  1122→      case '!cd': {
  1123→        const target = parts.slice(1).join(' ');
  1124→        if (!target) {
  1125→          if (session.threadId) {
  1126→            await this.discord.sendToThread(session.threadId, `当前目录: \`${collapseHome(session.cwd)}\`\n用法: \`!cd <path-or-name>\``);
  1127→          }
  1128→          return;
  1129→        }
  1130→
  1131→        // Resolve: absolute path, ~ expansion, or fuzzy (zoxide + sessions)
  1132→        let resolved: string | null = null;
  1133→        if (target.startsWith('/')) {
  1134→          resolved = target;
  1135→        } else if (target.startsWith('~')) {
