  1176→        const forkPrompt = parts.slice(1).join(' ') || 'Continue from the forked point.';
  1177→        try {
  1178→          if (session.threadId) {
  1179→            await this.discord.sendToThread(session.threadId, '🔀 正在 fork 当前 session...');
  1180→          }
  1181→          await this.sdkManager.startSession(forkPrompt, {
