  1273→  private extractRecoveryToken(text: string): string | null {
  1274→    const match = text.match(/^(?:(?:恢复|继续|resume|continue)\s+)?(dst-\d{4,8}-[\w-]+)$/i);
  1275→    return match?.[1] || null;
  1276→  }
