  1278→  private async handleRecoveryToken(session: CLISession, threadId: string): Promise<void> {
  1279→    if (!session.threadId) return;
  1280→
  1281→    try {
  1282→      const module = await this.loadMindkeeperBootstrapModule();
  1283→      if (!module) {
  1284→        await this.discord.sendToThread(
  1285→          session.threadId,
  1286→          `⚠️ 当前找不到 MindKeeper bootstrap 模块，无法解析恢复口令 \`${threadId}\`。`,
  1287→        );
  1288→        return;
  1289→      }
  1290→
  1291→      const quickResume = module.bootstrapQuick({
  1292→        repo: session.cwd,
  1293→        task: `恢复 ${threadId}`,
  1294→        thread: threadId,
  1295→      });
  1296→      const formatted = module.formatQuickResume(quickResume);
  1297→      await this.discord.sendToThread(
  1298→        session.threadId,
  1299→        [
  1300→          '**恢复上下文**',
  1301→          formatted,
  1302→          '',
  1303→          '恢复口令现在会先在 agent-im 内解析，不会再误发给 Claude SDK。',
  1304→        ].join('\n\n'),
  1305→      );
  1306→    } catch (err) {
  1307→      const errMsg = err instanceof Error ? err.message : String(err);
  1308→      await this.discord.sendToThread(session.threadId, `❌ 恢复失败: ${errMsg}`);
  1309→    }
  1310→  }
