  1312→  private getSessionInteractionMode(session: CLISession): { label: string; hint: string } {
  1313→    if (session.agent === 'codex') {
  1314→      return {
  1315→        label: 'observe-only',
  1316→        hint: 'Codex 自动发现 session 目前只转发输出，线程内回复不会注回本地终端。',
  1317→      };
  1318→    }
  1319→    if (session.source === 'hook') {
  1320→      return {
  1321→        label: 'interactive-when-idle',
  1322→        hint: '等本地 Claude Code session 进入 idle 后再在这里回复；如果本地仍是 active，agent-im 会提示等待。',
  1323→      };
  1324→    }
  1325→    return {
  1326→      label: 'interactive',
  1327→      hint: '这个线程内的回复会通过 SDK session manager 继续执行。',
  1328→    };
  1329→  }
