  1331→  private async buildDistillMessage(session: CLISession): Promise<string> {
  1332→    const ctx = this.sessionContext.get(session.sessionId);
  1333→    const mode = this.getSessionInteractionMode(session);
  1334→    const latestPrompt = ctx?.latestPrompt?.trim() || '';
  1335→    const taskSummary = session.title || latestPrompt.split('\n')[0]?.trim() || '尚未捕获 prompt';
  1336→
  1337→    const recentFiles = Array.from(new Set((ctx?.recentPaths || []).slice(-8).reverse()))
  1338→      .map(filePath => this.formatDistillPath(session.cwd, filePath))
  1339→      .slice(0, 6);
  1340→
  1341→    const mindkeeperMessage = await this.buildMindkeeperDistillMessage(session, {
  1342→      mode,
  1343→      latestPrompt,
  1344→      taskSummary,
  1345→      recentFiles,
  1346→    });
  1347→    if (mindkeeperMessage) return mindkeeperMessage;
  1348→
  1349→    const carryLines = [
  1350→      `Project: ${session.project}`,
  1351→      `Branch: ${session.branch}`,
  1352→      `Directory: ${collapseHome(session.cwd)}`,
  1353→      `Source: ${session.source}`,
  1354→      `Mode: ${mode.label}`,
  1355→    ];
  1356→    if (session.model) carryLines.push(`Model: ${session.model}`);
  1357→    if (session.provider) carryLines.push(`Provider: ${session.provider}`);
  1358→    carryLines.push(`Current task: ${taskSummary}`);
  1359→    if (latestPrompt) carryLines.push(`Latest user prompt: ${latestPrompt}`);
  1360→    if (recentFiles.length > 0) carryLines.push(`Recent files: ${recentFiles.join(', ')}`);
