  1609→  /** Detect if tool activity targets a different project than session cwd */
  1610→  private detectEffectiveProject(sessionCwd: string, paths: string[]): string | null {
  1611→    if (paths.length < 3) return null;
  1612→    const cwdNorm = sessionCwd.endsWith('/') ? sessionCwd : sessionCwd + '/';
  1613→
  1614→    // Find paths outside session cwd
  1615→    const outsidePaths = paths.filter(p => p.startsWith('/') && !p.startsWith(cwdNorm));
  1616→    if (outsidePaths.length < 3 || outsidePaths.length / paths.length < 0.3) return null;
  1617→
  1618→    // Extract project name at the path divergence point
  1619→    const cwdParts = sessionCwd.split('/');
  1620→    const projects = new Map<string, number>();
  1621→
  1622→    for (const p of outsidePaths) {
  1623→      const parts = p.split('/');
  1624→      let divergeAt = 0;
  1625→      for (let i = 0; i < Math.min(parts.length, cwdParts.length); i++) {
  1626→        if (parts[i] !== cwdParts[i]) { divergeAt = i; break; }
  1627→        divergeAt = i + 1;
  1628→      }
  1629→      const name = parts[divergeAt];
  1630→      if (name) projects.set(name, (projects.get(name) || 0) + 1);
  1631→    }
  1632→
  1633→    let dominant: string | null = null;
  1634→    let maxCount = 0;
  1635→    for (const [name, count] of projects) {
  1636→      if (count > maxCount) { maxCount = count; dominant = name; }
  1637→    }
  1638→    return dominant;
  1639→  }
