  1673→  private parseInput(input: unknown): Record<string, unknown> {
  1674→    if (input !== null && typeof input === 'object') return input as Record<string, unknown>;
  1675→    if (typeof input === 'string') {
  1676→      try { return JSON.parse(input); } catch { return {}; }
  1677→    }
  1678→    return {};
  1679→  }
  1680→
  1681→  /** Extract readable text from Claude Code's various tool output formats */
  1682→  private extractOutputText(output: unknown): string {
  1683→    if (typeof output === 'string') return output;
  1684→    if (output === null || output === undefined) return '';
  1685→    if (Array.isArray(output)) {
  1686→      // [{type:"text", text:"..."}, ...] — Claude API content blocks
  1687→      const texts = output
  1688→        .filter((b) => b && typeof b === 'object' && (b as Record<string, unknown>).type === 'text')
  1689→        .map((b) => String((b as Record<string, unknown>).text || ''));
  1690→      return texts.length > 0 ? texts.join('\n') : JSON.stringify(output, null, 2);
  1691→    }
  1692→    if (typeof output === 'object') {
  1693→      const o = output as Record<string, unknown>;
  1694→      // Bash: {stdout, stderr, interrupted, ...}
  1695→      if (typeof o.stdout === 'string') {
  1696→        let text = o.stdout;
  1697→        if (typeof o.stderr === 'string' && o.stderr) text += `\n[stderr] ${o.stderr}`;
  1698→        return text;
  1699→      }
  1700→      if (typeof o.content === 'string') return o.content;                      // {content:"text"}
  1701→      if (Array.isArray(o.content)) return this.extractOutputText(o.content);   // {type:"tool_result",content:[...]}
  1702→      if (typeof o.output === 'string') return o.output;                        // {output:"text"}
  1703→      if (typeof o.text === 'string') return o.text;                            // {text:"..."}
  1704→      if (typeof o.result === 'string') return o.result;                        // {result:"text"}
  1705→      // Edit/Write: {filePath, success}
  1706→      if (typeof o.filePath === 'string' && typeof o.success === 'boolean') {
  1707→        return o.success ? `\u2713 ${o.filePath}` : `\u2717 ${o.filePath}`;
  1708→      }
  1709→      return JSON.stringify(output, null, 2);
  1710→    }
  1711→    return String(output);
  1712→  }
